//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "OP197",
    compID: "acb_inOutClsCd1,acb_crryinoutClsCd"
  }, {
    grpCd: "SD116",
    compID: "acb_packUnitCd"
  }, {
    grpCd: "OP475",
    compID: "acb_frgtKndCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  $c.sbm.execute($p, sbm_wrkPlCd); //작업장 조회 synchronous로 처리함.

  $p.setTimeout(function () {
    acb_wrkPlCd.focus();
  }, {
    "delay": 50
  });
  ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(acb_wrkPlCd.getSelectedIndex(), "bondZoneCd"));
  ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(acb_wrkPlCd.getSelectedIndex(), "bondZoneCd"));
  ed_fromDt.setValue(scwin.fromDt);
  ed_toDt.setValue(scwin.toDt);
  dma_condition.set("crryoutBtnYn", "N");
  dma_condition.set("listIoClsCd", "");
};

//-------------------------------------------------------------------------
// 반출통고목록등록
//-------------------------------------------------------------------------
scwin.f_qeryList = async function (div) {
  /*let ret = await $c.gus.cfValidate([acb_inOutClsCd1, acb_wrkPlCd]);
  if (!ret) {
      return false;
  }*/
  if (!(await $c.gus.cfValidate($p, [acb_inOutClsCd1, acb_wrkPlCd], null, true))) return false;
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------------------------------------
// 반출 단축 저장
//-------------------------------------------------------------------------
scwin.f_CrryoutSave = function () {
  try {
    if (dma_condition.get("listIoClsCd") == 'O') {
      $c.win.alert($p, "반입조회 후 반출 기능을 이용하십시오");
    } else {
      var v_features = "copyHeader=yes,rowFrom=" + ds_searchResult.getRowPosition() + ",rowCnt=1";
      $c.gus.cfCopyDataSet($p, ds_searchResult, ds_searchResultCrryout, v_features);
      dma_condition.set("crryoutBtnYn", "Y");
      dma_condition.set("ioClsCd", "O");
      acb_crryinoutClsCd.setValue(acb_inOutClsCd1.getValue());
      scwin.f_qeryList();
    }
  } catch (e) {
    console.log("f_CrryoutSave : " + e);
  }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  try {
    /* ASIS 가우스 상태
    0 :Normal
    1:Insert
    2:Delete 
    3:Update
    4:Logical
    */

    if (!(ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "sndClsNm") == "미전송" || ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "sndClsNm") == "오류") && ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "U" //ds_searchResult.RowStatus(ds_searchResult.RowPosition) == 3 
    ) {
      $c.win.alert($p, "전송구분이 오류, 미전송 일때만 수정가능합니다.");
      return false;
    }
    if (!(ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "C" || ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "U" || ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "D")) {
      $c.win.alert($p, "변경된 데이터가 없습니다.");
      return false;
    }

    /*if (!await $c.gus.cfValidate([tbl_master])) {
        return;
    }*/
    if (!(await $c.gus.cfValidate($p, [tbl_master], null, true))) return false;

    //TOBE ASIS ds_searchResult 정보 바인드를 위해 해당 위치에 신규인 경우에만 추가함.
    if (ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "C") {
      ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "bondZoneCd", ed_bondZoneCd.getValue());
    }
    scwin.f_copyDataSetForSaveTransfer();

    //delete 표시
    if (ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "D" && ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "") {
      ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "D");
    }

    //update 표시
    if (ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "") {
      ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "U");
    }

    //반입시 필수 check
    if ((ds_dstSetForSaveTransfer.getCellData(0, "shedEndDt") == "" || ds_dstSetForSaveTransfer.getCellData(0, "shedRsn") == "") && ds_dstSetForSaveTransfer.getCellData(0, "crryinoutClsCd") == "I") {
      $c.win.alert($p, "반입시 장치종료일자와 장치위치는 필수 입력사항입니다.");
      return false;
    }

    //반출시 check 반입신고번호 필수입력 체크
    if (ds_dstSetForSaveTransfer.getCellData(0, "crryinoutClsCd") == "O") {
      if (ds_dstSetForSaveTransfer.getCellData(0, "ed_crryinDeclarNo2") == "") {
        $c.win.alert($p, "반출시 반입신고번호는 필수 입력사항입니다.");
        return false;
      }
      if (ds_dstSetForSaveTransfer.getCellData(0, "ed_crryinDeclarNo2") != "" && ed_crryinDeclarNo2.getValue().length != 10) {
        $c.win.alert($p, "반입신고번호는 년도(2)+일련번호(8) 총 10자리 입니다.");
        return false;
      }
      //조건이 맞으면 string을 합쳐준다.
      ds_dstSetForSaveTransfer.setCellData(0, "crryinDeclarNo", ed_bondZoneCdIn.getValue() + ed_crryinDeclarNo2.getValue());
    }
    if (ds_dstSetForSaveTransfer.getCellData(0, "chkFlag") == "I" && ds_dstSetForSaveTransfer.getCellData(0, "declarDt") == "") {
      ds_dstSetForSaveTransfer.setCellData(0, "declarDt", scwin.toDt);
    }
    ds_dstSetForSaveTransfer.setCellData(0, "wrkPlCd", acb_wrkPlCd.getValue());
    $c.sbm.execute($p, sbm_save);
    ;
  } catch (e) {
    console.log("f_Save : " + e);
  }
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_condition, null);
  acb_wrkPlCd.setSelectedIndex(0);
  ed_fromDt.setValue(scwin.fromDt);
  ed_toDt.setValue(scwin.toDt);
  acb_wrkPlCd.focus();
};

//-------------------------------------------------------------------------
// 전송버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_transfer = async function () {
  if (!(ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "sndClsNm") == "미전송" || ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "sndClsNm") == "오류")) {
    await $c.gus.cfAlertMsg($p, "미전송, 오류인 건만 전송할 수 있습니다.");
    return false;
  }
  scwin.f_copyDataSetForSaveTransfer();
  ds_dstSetForSaveTransfer.setCellData(0, "chkFlag", "T");
  $c.sbm.execute($p, sbm_save);
};

//-------------------------------------------------------------------------
// 전송, 저장전 호출하여 LISt 가 아닌 DTO 단위로만 넘긴다. 1건 처리
//-------------------------------------------------------------------------
scwin.f_copyDataSetForSaveTransfer = function () {
  var v_features = "copyHeader=no,rowFrom=" + ds_searchResult.getRowPosition() + ",rowCnt=1";
  $c.gus.cfCopyDataSet($p, ds_searchResult, ds_dstSetForSaveTransfer, v_features);
};

//-------------------------------------------------------------------------
// 전송구분 오류 팝업호출
//-------------------------------------------------------------------------
scwin.f_errorPopUp = function (row) {
  var docCd = "";
  if (ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "crryinoutClsCd") == "I") {
    docCd = "5HA";
  } else if (ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "crryinoutClsCd") == "O") {
    docCd = "5HB";
  }
  var declarNo = ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "declarNo");
  var deg = 0;
  var procClsCd = "D";
  let data = {
    deg: deg,
    docCd: docCd,
    declarNo: declarNo,
    procClsCd: procClsCd
  };
  let opts = {
    id: "sd_401_05_04p",
    popupName: "작업단위조회팝업",
    modal: false,
    type: "browserPopup",
    width: 860,
    height: 580,
    title: "작업단위조회팝업"
  };
  $c.win.openPopup($p, "/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);
};

//-------------------------------------------------------------------------
// 수량단위 변경시
//-------------------------------------------------------------------------
scwin.f_chgCntWt = function () {
  try {
    if (ds_searchResultCrryout.getRowCount > 0) {
      if (ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "crryoutBtnYn") == "1") {
        if (ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "cnt") > ds_searchResultCrryout.getCellData(0, "cntLimit")) {
          $c.win.alert($p, "잔여 수량보다 많습니다.");
          ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "cnt", ds_searchResultCrryout.getCellData(0, "cntLimit"));
          return;
        } else if (ds_searchResult.getCellData(ds_searchResult.getRowPosition(), "wt") > ds_searchResultCrryout.getCellData(0, "wtLimit")) {
          $c.win.alert($p, "잔여 중량보다 많습니다.");
          ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "wt", ds_searchResultCrryout.getCellData(0, "wtLimit"));
          return;
        }
      }
    }
  } catch (e) {
    console.log("f_chgCntWt : " + e);
  }
};

//-------------------------------------------------------------------------
// 행추가 클릭시
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
  try {
    if (ds_searchResult.getRowCount() == 0) {
      $c.win.alert($p, "조회를 먼저 하셔야 합니다.");
      return false;
    }
    var newRow = ds_searchResult.insertRow();
    gr_Regist.setFocusedCell(newRow, "crryinoutClsCd", false);

    //freeform 셋팅
    ed_bondZoneCdIn.setValue(ds_wrkPlCd.getCellData(acb_wrkPlCd.getSelectedIndex(), "bondZoneCd")); //반입신고번호
    ed_bondZoneCd.setValue(ds_wrkPlCd.getCellData(acb_wrkPlCd.getSelectedIndex(), "bondZoneCd")); //작업장
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "chkFlag", "I");
    acb_crryinoutClsCd.setValue(acb_inOutClsCd1.getValue()); //반출입구분

    ed_declarNoBondZoneCd.setValue(ds_wrkPlCd.getCellData(acb_wrkPlCd.getSelectedIndex(), "bondZoneCd")); //신고번호
    acb_bondZoneClsCd.setValue(ds_searchResult.getCellData(ds_searchResult.getRowPosition() - 1, "bondZoneClscd")); //보세구역구분

    if (acb_inOutClsCd1.getValue() == "I") {
      $c.gus.cfDisableObjects($p, [tbl_out]);
      $c.gus.cfEnableObjects($p, [tbl_in]);
    } else if (acb_inOutClsCd1.getValue() == "O") {
      $c.gus.cfDisableObjects($p, [tbl_in]);
      $c.gus.cfEnableObjects($p, [tbl_out]);
      ed_crryinDeclarNo2.setDisabled(false);
    }
    acb_bondZoneClsCd.setDisabled(false);
  } catch (e) {
    console.log("f_chf_AddRowgCntWt : " + e);
  }
};
//-------------------------------------------------------------------------
// 그리드 행삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = async function (e) {
  try {
    if (ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "C") {
      ds_searchResult.removeRow(ds_searchResult.getRowPosition());
      gr_Regist.removeFocusedCell(); //선택되어진 셀의 포커스 삭제
    } else {
      let delRowPosi = ds_searchResult.getRowPosition();
      ds_searchResult.deleteRow(delRowPosi);
      $c.gus.cfGoPrevPosition($p, gr_Regist, delRowPosi);
    }
  } catch (e) {
    console.log("f_DelRow : " + e);
  }
};

//-------------------------------------------------------------------------
// 그리드취소
//-------------------------------------------------------------------------
scwin.f_CancelRow = function (e) {
  try {
    if (ds_searchResult.getRowStatus(ds_searchResult.getRowPosition()) == "C") {
      ds_searchResult.removeRow(ds_searchResult.getRowPosition());
    } else {
      ds_searchResult.undoRow(ds_searchResult.getRowPosition());
    }
    $c.gus.cfGoPrevPosition($p, gr_Regist, 0); //ASIS취소버튼 클릭시 첫번째 행으로 이동함.
  } catch (e) {
    console.log("f_CancelRow : " + e);
  }
};
///////////////////////////////////////////// S U B M I S S I O N    E V E N T /////////////////////////////////////////

//-------------------------------------------------------------------------
// 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    //$c.gus.cfShowError(sbm_retrieve);
    return;
  }
  if (ds_searchResult.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, "조회된 데이타가 없습니다.");
  } else {
    ed_bondZoneCd.setValue(ds_searchResult.getCellData(0, "bondZoneCd"));
    if (acb_inOutClsCd1.getValue() == "I") {
      //$c.gus.cfDisableObjects([tbl_out]);
      //$c.gus.cfEnableObjects([tbl_in]);
      //$c.gus.cfEnableObjects([btn_crryout]);
      //disable 처리가 무슨이유인지 맞지않음 함수처리하지 않고 직접정의함. (ASIS 반출버튼도 나옴)
      ed_crryinDeclarNo2.setDisabled(true);
      btn_crryout.setDisabled(false);
      ed_shedEndDt.setDisabled(false); //장치종료일자
      ed_shedRsn.setDisabled(false); //장치위치
      dma_condition.set("listIoClsCd", "I");
    } else if (acb_inOutClsCd1.getValue() == "O") {
      $c.gus.cfDisableObjects($p, [tbl_in]);
      $c.gus.cfEnableObjects($p, [tbl_out]);
      $c.gus.cfDisableObjects($p, [btn_crryout]);
      dma_condition.set("listIoClsCd", "O");
    }
    acb_bondZoneClsCd.setDisabled(true);
  }
  tbx_totalRows.setValue(ds_searchResult.getRowCount());
  $c.gus.cfGoPrevPosition($p, gr_Regist, 0); //첫번째 포커스 이동
  //gr_Regist.setFocusedCell(0, "crryinoutClsCd", true);

  // 반출 버튼 클릭으로 조회 후
  if (dma_condition.get("crryoutBtnYn") == "Y") {
    dma_condition.set("crryoutBtnYn", "N");
    scwin.f_AddRow();
    $c.gus.cfDisableObjects($p, [tbl_in]);
    $c.gus.cfEnableObjects($p, [tbl_out]);
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "crryinDeclarNo", ds_searchResultCrryout.getCellData(0, "declarNoOthers"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "cnt", ds_searchResultCrryout.getCellData(0, "cntLimit"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "packUnitCd", ds_searchResultCrryout.getCellData(0, "packUnitCd"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "wt", ds_searchResultCrryout.getCellData(0, "wtLimit"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "mchtNmCmpy", ds_searchResultCrryout.getCellData(0, "mchtNmCmpy"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "mchtname", ds_searchResultCrryout.getCellData(0, "mchtname"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "frgtKndCd", ds_searchResultCrryout.getCellData(0, "frgtKndCd"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "addr1", ds_searchResultCrryout.getCellData(0, "addr1"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "addr2", ds_searchResultCrryout.getCellData(0, "addr2"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "addr3", ds_searchResultCrryout.getCellData(0, "addr3"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "comm1", ds_searchResultCrryout.getCellData(0, "comm1"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "comm2", ds_searchResultCrryout.getCellData(0, "comm2"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "comm3", ds_searchResultCrryout.getCellData(0, "comm3"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "comm4", ds_searchResultCrryout.getCellData(0, "comm4"));
    ds_searchResult.setCellData(ds_searchResult.getRowPosition(), "crryoutBtnYn", "1");
    $c.gus.cfGoPrevPosition($p, gr_Regist, ds_searchResult.getRowCount()); //반출버튼으로 처리시 마지막으로 포커스 이동
  }
};

//-------------------------------------------------------------------------
// 작업장 콜백
//-------------------------------------------------------------------------
scwin.sbm_wrkPlCd_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    //$c.gus.cfShowError(sbm_retrieve);
    return;
  }
  ds_wrkPlCd.sort("wrkPlCd", 0); // [0,1,2] 정렬 옵션 (0: 오름차순, 1: 내림차순, 2: 정렬 취소) +wrkPlCd
};

//-------------------------------------------------------------------------
// 저장 콜백
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    //$c.gus.cfShowError(sbm_retrieve);
    return;
  }
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다

  ds_searchResultCrryout.removeAll();
  $c.sbm.execute($p, sbm_retrieve);
};

